"use strict";parserFactory.register("nanomashin.online",()=>new NanomashinonlineParser);class NanomashinonlineParser extends Parser{constructor(){super()}async getChapterUrls(e,r){return(await this.walkTocPages(e,NanomashinonlineParser.chaptersFromDom,NanomashinonlineParser.nextTocPageUrl,r)).reverse()}static chaptersFromDom(e){return[...e.querySelectorAll("h3 a")].map(e=>util.hyperLinkToChapter(e))}static nextTocPageUrl(e){return e.querySelector("nav button[rel='next']")?.parentNode?.href??null}findContent(e){return e.querySelector("article div.pt-10")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return e.querySelector("body img[decoding]")?.src??null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.pt-2")]}}